import{_ as a,o as n,c as s,a3 as e}from"./chunks/framework.Daqi0Atb.js";const g=JSON.parse('{"title":"11｜记忆模块导论：从草稿纸到长期记忆，建立 Agent 的经验沉淀秩序","description":"","frontmatter":{},"headers":[],"relativePath":"courses/agent-design/11-记忆模块导论：从草稿纸到长期记忆，建立 Agent 的经验沉淀秩序.md","filePath":"courses/agent-design/11-记忆模块导论：从草稿纸到长期记忆，建立 Agent 的经验沉淀秩序.md"}'),r={name:"courses/agent-design/11-记忆模块导论：从草稿纸到长期记忆，建立 Agent 的经验沉淀秩序.md"};function o(d,t,i,l,p,h){return n(),s("div",null,[...t[0]||(t[0]=[e(`<h1 id="_11-记忆模块导论-从草稿纸到长期记忆-建立-agent-的经验沉淀秩序" tabindex="-1">11｜记忆模块导论：从草稿纸到长期记忆，建立 Agent 的经验沉淀秩序 <a class="header-anchor" href="#_11-记忆模块导论-从草稿纸到长期记忆-建立-agent-的经验沉淀秩序" aria-label="Permalink to &quot;11｜记忆模块导论：从草稿纸到长期记忆，建立 Agent 的经验沉淀秩序&quot;">​</a></h1><p><strong>作者</strong>：黄佳</p><hr><h2 id="一句话脉络" tabindex="-1">一句话脉络 <a class="header-anchor" href="#一句话脉络" aria-label="Permalink to &quot;一句话脉络&quot;">​</a></h2><p>感知模块结束，进入记忆模块。记忆不是&quot;让 Agent 记住东西&quot;这么简单——它真正要解决的是<strong>防止长程任务在时间中漂移</strong>。</p><hr><h2 id="《记忆碎片》的启示" tabindex="-1">《记忆碎片》的启示 <a class="header-anchor" href="#《记忆碎片》的启示" aria-label="Permalink to &quot;《记忆碎片》的启示&quot;">​</a></h2><p>电影主角患短期记忆障碍，新的记忆无法稳定变成长记忆。他靠外部线索（照片、纸条、纹身）把关键事实留在身体和物件上——给自己搭了一套外部记忆系统。</p><p>Agent 也一样。窗口一关、会话一结束，Agent 就变回对你和你的项目都不熟悉的陌生人。</p><p><strong>记忆设计 = 给 Agent 留下照片、纸条和纹身</strong></p><hr><h2 id="记忆要解决的真正问题" tabindex="-1">记忆要解决的真正问题 <a class="header-anchor" href="#记忆要解决的真正问题" aria-label="Permalink to &quot;记忆要解决的真正问题&quot;">​</a></h2><h3 id="开篇案例-auth-py-重构-agent" tabindex="-1">开篇案例：auth.py 重构 Agent <a class="header-anchor" href="#开篇案例-auth-py-重构-agent" aria-label="Permalink to &quot;开篇案例：auth.py 重构 Agent&quot;">​</a></h3><p>一个负责代码重构的 Agent，在前面几轮发现了 <code>UserSession</code> 和 <code>PermissionCache</code> 之间的循环依赖，横跨四个文件，建议先抽共享 <code>types.py</code>。</p><p>Session 3 结束时，进度摘要这样写：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>已完成：</span></span>
<span class="line"><span>- 确认 UserSession 与 PermissionCache 存在循环依赖</span></span>
<span class="line"><span>- 建议先引入共享 types.py</span></span>
<span class="line"><span>待继续：</span></span>
<span class="line"><span>- 开始移动 UserSession 相关代码</span></span></code></pre></div><p>Session 4 的 Agent 看到这句话，做出了一个&quot;合理但危险&quot;的解释：先把 UserSession 移到新模块，<strong>再在移动过程中顺手补 types.py</strong>。结果：43 个测试失败，CI 无法继续，项目回滚。</p><p><strong>丢失的最关键信息</strong>：</p><ul><li>循环依赖的<strong>具体路径</strong></li><li>已经被排除的<strong>错误做法</strong></li><li><strong>禁止动作</strong>：不要先移动 UserSession</li></ul><h3 id="长程-agent-的五种迷失" tabindex="-1">长程 Agent 的五种迷失 <a class="header-anchor" href="#长程-agent-的五种迷失" aria-label="Permalink to &quot;长程 Agent 的五种迷失&quot;">​</a></h3><table tabindex="0"><thead><tr><th>迷失类型</th><th>表现</th></tr></thead><tbody><tr><td><strong>目标漂移</strong></td><td>从&quot;完成 auth.py 重构&quot;变成&quot;把这个 import error 修干净&quot;</td></tr><tr><td><strong>状态漂移</strong></td><td>Agent 以为环境是 A，真实环境已经是 B</td></tr><tr><td><strong>错误放大</strong></td><td>第一步误判 schema 字段，后面查询验证文档都顺着误判长出来</td></tr><tr><td><strong>细节过载</strong></td><td>围着一个 Warning Message 把预算耗完</td></tr><tr><td><strong>完成幻觉</strong></td><td>todo 都打勾了当成目标达成</td></tr></tbody></table><hr><h2 id="记忆是-pra-循环的时间维度" tabindex="-1">记忆是 PRA 循环的时间维度 <a class="header-anchor" href="#记忆是-pra-循环的时间维度" aria-label="Permalink to &quot;记忆是 PRA 循环的时间维度&quot;">​</a></h2><p>PRA 循环（感知 → 推理 → 行动）解决的是&quot;这一轮&quot;的问题。</p><p>记忆解决的是<strong>时间问题</strong>：上一轮的感知、推理、行动，怎样影响下一轮？</p><hr><h2 id="四种记忆类型" tabindex="-1">四种记忆类型 <a class="header-anchor" href="#四种记忆类型" aria-label="Permalink to &quot;四种记忆类型&quot;">​</a></h2><table tabindex="0"><thead><tr><th>类型</th><th>说明</th><th>对应模式</th></tr></thead><tbody><tr><td><strong>Working Memory</strong></td><td>当前 context window 里正在用的信息</td><td>分层保留</td></tr><tr><td><strong>Scratchpad（草稿纸）</strong></td><td>当前任务里的工作台，暂存中间判断、工具结果分析、下一步计划</td><td>分层保留</td></tr><tr><td><strong>Episodic / Semantic / Procedural</strong></td><td>跨会话的长期记忆</td><td>进度追踪 / RAG / 技能包</td></tr><tr><td><strong>Memory Trace</strong></td><td>记忆的仪表盘：写入、取回、使用、淘汰的记录</td><td>各模式</td></tr></tbody></table><h3 id="scratchpad-是最容易被低估的" tabindex="-1">Scratchpad 是最容易被低估的 <a class="header-anchor" href="#scratchpad-是最容易被低估的" aria-label="Permalink to &quot;Scratchpad 是最容易被低估的&quot;">​</a></h3><blockquote><p>它是记忆工作台，不是档案馆。</p></blockquote><p>工具调用刚回来，规则还没核完，几个方案还没排除，下一步还没定——这些先放工作台。任务收束后，再决定哪些扔掉、哪些写进度追踪、哪些进失败日记、哪些进长期知识库。</p><hr><h2 id="记忆的生命周期" tabindex="-1">记忆的生命周期 <a class="header-anchor" href="#记忆的生命周期" aria-label="Permalink to &quot;记忆的生命周期&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>context window（上下文窗口）</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>scratchpad（草稿纸）</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>structured trace（结构化追踪）</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>long-term memory（长程记忆）</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>retrieval / replay / forgetting（检索/重放/遗忘）</span></span></code></pre></div><hr><h2 id="记忆模式组的四种模式" tabindex="-1">记忆模式组的四种模式 <a class="header-anchor" href="#记忆模式组的四种模式" aria-label="Permalink to &quot;记忆模式组的四种模式&quot;">​</a></h2><p>记忆组四讲 = <strong>架、取、录、省</strong></p><table tabindex="0"><thead><tr><th>模式</th><th>解决</th><th>关键字</th></tr></thead><tbody><tr><td><strong>分层保留</strong>（第一讲）</td><td>架</td><td>记忆的货架怎么搭</td></tr><tr><td><strong>检索增强 RAG</strong>（第二讲）</td><td>取</td><td>语义记忆怎么取回来</td></tr><tr><td><strong>进度追踪</strong>（第三讲）</td><td>录</td><td>情节记忆怎么沉淀</td></tr><tr><td><strong>失败日记</strong>（第四讲）</td><td>省</td><td>失败经验怎么召回</td></tr></tbody></table><hr><h2 id="记忆的四个工程问题" tabindex="-1">记忆的四个工程问题 <a class="header-anchor" href="#记忆的四个工程问题" aria-label="Permalink to &quot;记忆的四个工程问题&quot;">​</a></h2><ol><li>什么信息只该留在 context window 里？</li><li>什么信息该先放 scratchpad，等任务收束再决定去留？</li><li>什么信息应该写进长期记忆，并在需要时准确召回？</li><li>什么信息已经过期，应该被淘汰或降权？</li></ol><hr><h2 id="记忆框架选型" tabindex="-1">记忆框架选型 <a class="header-anchor" href="#记忆框架选型" aria-label="Permalink to &quot;记忆框架选型&quot;">​</a></h2><table tabindex="0"><thead><tr><th>框架</th><th>特点</th></tr></thead><tbody><tr><td><strong>Letta</strong></td><td>Agent 在 core / archival / recall 等记忆层之间自己搬运</td></tr><tr><td><strong>Mem0</strong></td><td>单遍层次抽取 + 多信号检索</td></tr><tr><td><strong>Zep</strong></td><td>时序知识图谱，擅长表示&quot;事实随时间怎么变&quot;</td></tr><tr><td><strong>Anthropic Memory Tool</strong></td><td>底层，Agent 直接读写持久化记忆目录</td></tr></tbody></table><blockquote><p>建议不要同时上两套记忆系统。记忆有单一事实来源问题。</p></blockquote><hr><h2 id="记忆不是存储的堆叠-而是经验的治理" tabindex="-1">记忆不是存储的堆叠，而是经验的治理 <a class="header-anchor" href="#记忆不是存储的堆叠-而是经验的治理" aria-label="Permalink to &quot;记忆不是存储的堆叠，而是经验的治理&quot;">​</a></h2><h3 id="记忆注入-memory-injection-风险" tabindex="-1">记忆注入（Memory Injection）风险 <a class="header-anchor" href="#记忆注入-memory-injection-风险" aria-label="Permalink to &quot;记忆注入（Memory Injection）风险&quot;">​</a></h3><p>当线索被选择性记录、被错误解释、甚至被故意篡改时，记忆会变成制造幻觉的机器。</p><p>未来 Agent 攻击可能包括：</p><ul><li><strong>记忆注入</strong>：先错误线索写入外部记忆</li><li><strong>记忆投毒</strong>：污染 Agent 对用户、项目和历史任务的理解</li><li><strong>记忆篡改</strong>：让 Agent 沿着错误方向继续行动</li></ul><p><strong>记忆需要在设计时就考虑</strong>：写入什么、谁有权改、什么时候过期、下次如何召回、召回后是否真的被用上。</p><hr><h2 id="memory-trace-记忆的行车记录仪" tabindex="-1">Memory Trace：记忆的行车记录仪 <a class="header-anchor" href="#memory-trace-记忆的行车记录仪" aria-label="Permalink to &quot;Memory Trace：记忆的行车记录仪&quot;">​</a></h2><p>出了问题，顺着这串追问追：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>这次行动需要依赖哪段过去经验？</span></span>
<span class="line"><span>这段经验当时有没有被写入记忆？</span></span>
<span class="line"><span>如果写了，这次为什么没被召回？（没命中？被淘汰？召回后和场景对不上？）</span></span>
<span class="line"><span>如果没写，是哪个环节本该写却没写？</span></span>
<span class="line"><span>下一版，你会怎么改记忆 pipeline？</span></span></code></pre></div><p>每环都可能出问题：</p><ul><li>没有写入 → 沉淀问题</li><li>没有取回 → 检索问题</li><li>取回不用 → 推理或规划问题</li><li>用了还错 → 记忆质量或适用边界问题</li></ul><hr><h2 id="感知-vs-记忆-边界在哪里" tabindex="-1">感知 vs 记忆：边界在哪里？ <a class="header-anchor" href="#感知-vs-记忆-边界在哪里" aria-label="Permalink to &quot;感知 vs 记忆：边界在哪里？&quot;">​</a></h2><ul><li><strong>感知</strong>关心的是<strong>空间</strong>——这一轮会话里，Agent 看到了什么</li><li><strong>记忆</strong>关心的是<strong>时间</strong>——当前窗口关掉之后，怎么把有用的东西沉淀下来</li></ul><p>一份长期保留的 CLAUDE.md，你说它是感知（因为决定这一轮看到什么）也对，说是记忆（因为跨会话留下来了）也对。<strong>把边界想清楚，对设计系统很有帮助。</strong></p>`,62)])])}const u=a(r,[["render",o]]);export{g as __pageData,u as default};
